class taxstatus_Page1 extends TabbedPage
{
	 protected function populateForm()
	{
		$this->addTabs();
		$fs = $this->form->addElement('fieldset')->setLabel('taxstatus page 1');
		$buttonGroup = $fs->addElement('group'); 
		$buttonGroup->addElement('submit', $this->getButtonName('back'), array('value' => '<< Back')); 
		$buttonGroup->addElement('submit', $this->getButtonName('submit'), array('value' => 'Finish')); 
		$buttonGroup->addElement('submit', $this->getButtonName('next'), array('value' => 'Next >>')); 
		$this->setDefaultAction('next', 'empty.gif');
		$this->addGlobalSubmit();
		$idtaxstatus = $fs->addElement('text', 'idtaxstatus', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Index' )
;
		$taxstatus = $fs->addElement('text', 'taxstatus', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Tax Status' )
			->addFilter( 'trim' )
;
		$notes = $fs->addElement('text', 'notes', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Notes' )
			->addFilter( 'trim' )
;
	$createduser = $fs->addElement('text', 'createduser', array() )
	->setLabel( 'Created By User' )
	->addFilter( 'trim' )
;
		$createddate = $fs->addElement('text', 'createddate', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Created Date' )
			->addFilter( 'trim' )
;
		$updateduser = $fs->addElement('text', 'updateduser', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Updated by User' )
			->addFilter( 'trim' )
;
	}
}

